const path = require('path');

const PROBLEMS_DATA_PATH = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(PROBLEMS_DATA_PATH, 'utf8');
  return JSON.parse(raw);
}

/**
 * List problems with filtering, paging, sorting, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - difficulty filter, e.g. 'Easy', 'Medium', 'Hard'
 * @param {boolean} [options.includeComponents] - whether to include sorted componentLanguages array
 * @param {number} [options.limit=50] - max number of results to return, capped at 50
 * @returns {Object} result with problems array and metadata
 */
function listProblems({ difficulty, includeComponents = false, limit = 50 } = {}) {
  const allProblems = loadProblems();

  // Normalize limit and cap at 50
  const appliedLimit = Math.min(limit || 50, 50);

  // Filter by difficulty if provided
  let filtered = allProblems;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply limit
  const limited = filtered.slice(0, appliedLimit);

  // Prepare problems with optional sorted componentLanguages
  const problems = limited.map(p => {
    const problemCopy = { ...p };
    if (includeComponents && Array.isArray(problemCopy.componentLanguages)) {
      problemCopy.componentLanguages = [...problemCopy.componentLanguages].sort();
    }
    return problemCopy;
  });

  // Compute difficulty breakdown on filtered set
  const difficultyBreakdown = filtered.reduce((acc, p) => {
    acc[p.difficulty] = (acc[p.difficulty] || 0) + 1;
    return acc;
  }, {});

  return {
    problems,
    totalProblems: allProblems.length,
    filteredCount: filtered.length,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
